module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output reg [9:0] data_out
);
// TODO: Implement the functionality described in the specification.
// Step 1: Accumulate four valid input data_in values and calculate the output reg data_out by adding these four values together.
// Step 2: If there are fewer than four data_in inputs, do not output the accumulated sum.
// Step 3: When the four data_in inputs are accumulated, set valid_out to 1 for one cycle.
// Step 4: The output reg data_out is the accumulated sum of the four input data_in values.
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        valid_out <= 0;
        data_out <= 0;
    end else if (valid_in) begin
        if (cnt == 3'b100) begin
            data_out <= data_out + data_in;
            valid_out <= 1;
        end else begin
            data_out <= data_out + data_in;
            valid_out <= 0;
        end
    end
end
endmodule
